-- Recalculate aforo_disponible based on en_curso accesses
UPDATE zonas z SET aforo_disponible = aforo_maximo - (SELECT COUNT(*) FROM accesos_vehiculares a WHERE a.zona_id = z.id AND a.estado = 'en_curso');

